  3→/// Helper: creates a reqwest client with cookie store and no redirect following.
  4→fn authenticated_client() -> reqwest::Client {
  5→    reqwest::Client::builder()
  6→        .cookie_store(true)
  7→        .redirect(reqwest::redirect::Policy::none())
  8→        .build()
  9→        .unwrap()
 10→}
 11→
 12→/// Helper: register a user and log them in, returning the cookie-jar client.
 13→async fn register_and_login(address: &str, email: &str, password: &str) -> reqwest::Client {
 14→    let client = authenticated_client();
 15→
 16→    // Register
 17→    let resp = client
 18→        .post(format!("{address}/register"))
 19→        .form(&[
 20→            ("email", email),
 21→            ("password", password),
 22→            ("password_confirmation", password),
 23→        ])
 24→        .send()
 25→        .await
 26→        .expect("Failed to register");
 27→    assert_eq!(resp.status().as_u16(), 303, "Registration should redirect");
 28→
 29→    // Login
 30→    let resp = client
 31→        .post(format!("{address}/login"))
 32→        .form(&[("email", email), ("password", password)])
 33→        .send()
 34→        .await
 35→        .expect("Failed to login");
 36→    assert_eq!(resp.status().as_u16(), 303, "Login should redirect");
 37→
 38→    client
 39→}
 40→
 41→/// Helper: get the first context ID from the contexts page
 42→async fn get_first_context_id(client: &reqwest::Client, address: &str) -> String {
 43→    let response = client
 44→        .get(format!("{address}/contexts"))
 45→        .send()
 46→        .await
 47→        .expect("Failed to GET /contexts");
 48→
 49→    let body = response.text().await.unwrap();
 50→    // Extract the first context ID from a delete form action
 51→    let action_prefix = "action=\"/contexts/";
 52→    let start = body.find(action_prefix).expect("Missing context action") + action_prefix.len();
 53→    let end = body[start..].find('/').expect("Missing / after context ID");
 54→    body[start..start + end].to_string()
 55→}
